from pybricks.parameters import Button, Stop
from pybricks.tools import StopWatch, multitask, run_task, wait

from pid_python import heading_pid
from robot_config import DRIVE_BASE, HUB, KD, KI, KP, LEFT_ATTACHMENT, RIGHT_ATTACHMENT, TURN_KD, TURN_KI, TURN_KP

# Set up all devices.
watch = StopWatch()

async def subtask():
    # previously 1100
    # 352
    await RIGHT_ATTACHMENT.run_angle(1000, 230)
    # 352

async def subtask2():
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, TURN_KP, TURN_KI, TURN_KD)
    # compare current heading to ideal current heading and adds the
    # difference to the turn
    await DRIVE_BASE.turn(0 - ((DRIVE_BASE.angle() - -90) + 195))
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, KP, KI, KD)
    await DRIVE_BASE.straight(70, then=Stop.BRAKE)

async def subtask3():
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, KP, KI, KD)
    await DRIVE_BASE.straight(250, then=Stop.BRAKE)

async def subtask4():
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, KP, KI, KD)
    await DRIVE_BASE.straight(600, then=Stop.BRAKE)
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, TURN_KP, TURN_KI, TURN_KD)
    await DRIVE_BASE.turn(105)

async def subtask5():
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, KP, KI, KD)
    await DRIVE_BASE.straight(-60, then=Stop.BRAKE)

async def subtask6():
    await DRIVE_BASE.straight(450, then=Stop.NONE)
    await DRIVE_BASE.arc(-700, distance=150)
    await DRIVE_BASE.straight(500)

async def subtask7():
    await wait(500)
    await RIGHT_ATTACHMENT.run_angle(1000, -784)

async def subtask8():
    watch.reset()
    print(HUB.battery.voltage())
    DRIVE_BASE.use_gyro(True)
    await DRIVE_BASE.straight(-10, then=Stop.BRAKE)
    await multitask(
        subtask(),
        DRIVE_BASE.straight(640, then=Stop.BRAKE),
    )
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, TURN_KP, TURN_KI, TURN_KD)
    await DRIVE_BASE.turn(-70)
    # new blcok for lower attachment
    await RIGHT_ATTACHMENT.run_angle(1000, 100)
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, KP, KI, KD)
    await DRIVE_BASE.straight(-100, then=Stop.BRAKE)
    await LEFT_ATTACHMENT.run_angle(1000, -170)
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, TURN_KP, TURN_KI, TURN_KD)
    await DRIVE_BASE.turn(-20)
    await wait(50)
    DRIVE_BASE.stop()
    await heading_pid(DRIVE_BASE, KP, KI, KD)
    await DRIVE_BASE.straight(105, then=Stop.BRAKE)
    # raise brush
    await RIGHT_ATTACHMENT.run_angle(1000, 450)
    await multitask(
        subtask2(),
        RIGHT_ATTACHMENT.run_angle(150, -600),
    )
    await DRIVE_BASE.straight(-25, then=Stop.BRAKE)
    await RIGHT_ATTACHMENT.run_angle(1000, 320)
    await wait(50)
    await heading_pid(DRIVE_BASE, TURN_KP, TURN_KI, TURN_KD)
